const data = $input.first().json;
const fields = data.fields;
const formFields = [];
const stripHtml = (str) => (str ?? '').toString().replace(/<[^>]*>/g, '');

// Build dynamic fields from template
for (const field of fields) {
  if (field.type === 'image' || field.type === 'logo') {
    // Preview
    formFields.push({
      fieldLabel: `${field.name} (preview)`,
      fieldType: "html",
      html: `<div style="padding:12px;border:1px solid #ddd;border-radius:12px;margin:8px 0">
               <p style="font-weight:bold;margin-bottom:8px">${field.name}</p>
               <img src="${field.currentValue}" width="300" height="auto" />
             </div>`
    });
    // File upload
    formFields.push({
      fieldLabel: `${field.name} (upload new)`,
      fieldType: "file",
      acceptFileTypes: ".png, .jpg, .jpeg, .svg, .webp",
      requiredField: false
    });
  } else if (field.type === 'text') {
    formFields.push({
      fieldLabel: `${field.name}`,
      fieldType: "text",
      placeholder: stripHtml(field.currentValue),
      defaultValue: stripHtml(field.currentValue),
      requiredField: false
    });
  } else if (field.type === 'container') {
    formFields.push({
      fieldLabel: `${field.name} (${field.attribute})`,
      fieldType: "text",
      placeholder: field.currentValue,
      defaultValue: field.currentValue,
      requiredField: false
    });
  }
}

// ADDITION: caption input for social media
formFields.push({
  fieldLabel: "caption for social media",
  fieldType: "text",
  placeholder: "Write the caption you want to publish with these images...",
  defaultValue: "",
  requiredField: false
});

return [
  {
    json: {
      templateId: data.templateId,
      formFields,
      totalFields: fields.length
    }
  }
];

const data = $input.first().json;
const base64Images = data.base64Images || {};
const design = $('Get a design').first().json;
const templateId = design.template_id;
const formats = design.formats;

const elements = {};
const hexRegex = /^#([0-9a-fA-F]{6}|[0-9a-fA-F]{8})$/;

for (const el of design.elements) {
  const name = el.name;
  const attr = el.attributes[0];
  const defaultVal = attr.values['facebook-post'];

  if (el.type === 'container') {
    let val = data[`${name} (${attr.id})`];
    if (attr.id === 'background_color') {
      val = (val && hexRegex.test(val)) ? val : defaultVal;
    }
    if (val) elements[name] = { [attr.id]: val };
  } else if (el.type === 'text') {
    const val = data[name] || defaultVal;
    if (val) elements[name] = { payload: val };
  } else if (el.type === 'image' || el.type === 'logo') {
    // Key format: details__upload_new_, product__upload_new_, logo__upload_new_
    const binaryKey = `${name}__upload_new_`;

    if (base64Images[binaryKey]) {
      const raw = base64Images[binaryKey].replace(/^data:[^;]+;base64,/, '');
      elements[name] = { image_encoded: raw };
    } else {
      elements[name] = { image_url: defaultVal };
    }
  }
}

return formats.map(f => ({
  json: {
    url: `https://api.abyssale.com/banner-builder/${templateId}/generate`,
    body: {
      template_format_name: f.id,
      elements
    },
    formatName: `${f.id} (${f.width}x${f.height})`
  }
}));

const jsonData = $input.first().json;
const binaryData = $input.first().binary || {};
const base64Images = {};

for (const key of Object.keys(binaryData)) {
  const buffer = await this.helpers.getBinaryDataBuffer(0, key);
  const mimeType = binaryData[key].mimeType;
  base64Images[key] = `data:${mimeType};base64,${buffer.toString('base64')}`;
}

return [{
  json: {
    ...jsonData,
    base64Images
  }
}];
